def compute_score() -> tuple[str, float]:
    # Use VLM to compare before/after screenshots for extraneous changes
    orig_img = [img for img in original_ppt_screenshots if img.slide_number == 5][0].image_path
    mod_img = [img for img in modified_ppt_screenshots if img.slide_number == 5][0].image_path
    prompt = (
        "Compare these two images of PowerPoint slides. Ignore the positions of the the graph and Miami report images on the slide. "
        "Are there any other changes to text, formatting, or layout? Respond 'No' if no changes except the image swap."
    )
    response = vlm_call(prompt, [orig_img, mod_img], temperature=0.2, max_tokens=100).strip().lower()
    if 'no' in response:
        return ("No unintended text/layout changes detected.", 1.0)
    else:
        return ("Extraneous text/layout changes detected.", 0.0)

def compute_score() -> tuple[str, float]:
    # Use ppt_diff to check for any modifications on slides other than 5
    modified_slides = set([s[0].slide_number for s in ppt_diff.modified_slides])
    added_slides = set([s.slide_number for s in ppt_diff.added_slides])
    removed_slides = set([s.slide_number for s in ppt_diff.removed_slides])
    extraneous = (modified_slides | added_slides | removed_slides) - {5}
    if not extraneous:
        return ("No changes to other slides.", 1.0)
    else:
        return (f"Changes detected on slides: {sorted(list(extraneous))}", 0.0)
